#include <iostream>
#include <unordered_set>
#include <vector>

using namespace std;

// Definition for singly-linked list.
class ListNode {
public:
    int val;
    ListNode* next;
    ListNode() {}
    ListNode(int val) { this->val = val; }n    ListNode(int val, ListNode* next) : val(val), next(next) {}
};

class Solution {
public:
bool hasDuplicates(ListNode* head);
};

class Solution {
public:
bool hasDuplicates(ListNode* head) {
    if (head == nullptr) return false;
    unordered_set<int> seen;
    seen.insert(head->val);
    ListNode* cur = head->next;
    while (cur != nullptr) {
        if (seen.find(cur->val) != seen.end()) return true;
        seen.insert(cur->val);
        cur = cur->next;
    }
    return false;
}
};

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int num : arr) {
        cur->next = new ListNode(num);
        cur = cur->next;
    }
    Solution solver;
    cout << (solver.hasDuplicates(&dummy) ? '1' : '0') << endl;
    return 0;
}
